+    heap.set_property(source, str_key("b"), int_val(2)).unwrap();
+    let target = heap.alloc_plain();
+    heap.set_property(target, str_key("c"), int_val(3)).unwrap();
+    heap.spread_into(target, source).unwrap();
+    assert_eq!(
